"""
mkt-context layer — 1 Timothy chapters 1–5 (fills all missing verses)
Output: data/commentary/mkt-context/1timothy.json
Run: python3 scripts/zc-context-1timothy-1-5-full.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {
  "1": {
    "1": "<p>Paul identifies himself as an apostle 'by the command of God our Savior and of Christ Jesus our hope' — the commission language is authoritative rather than consensual, grounding apostolic authority in divine mandate rather than community recognition. The title <em>sōtēr</em> (Savior) applied to God directly competed with the Roman imperial use of <em>sōtēr</em> for Augustus and subsequent emperors; the Pastoral Epistles' repeated use of the title for God and Christ is a deliberate counter-imperial claim.</p>",
    "2": "<p>Timothy's background: born in Lystra (Acts 16:1) to a Jewish mother Eunice and Greek father, he was circumcised by Paul before being brought on the missionary team (Acts 16:3) — a concession to Jewish communities along the route, since Timothy was known locally as uncircumcised. He served as Paul's most trusted representative (Phil 2:19-22: I have no one like him; 1 Cor 4:17: my beloved and faithful child in the Lord). The address 'my true son in the faith' (<em>gnēsiō teknō en pistei</em>) uses the language of legitimate birth — not adopted but genuinely Paul's spiritual offspring.</p>",
    "4": "<p>'Myths and endless genealogies' (<em>mythois kai genealogiais aperantois</em>) — the false teaching Timothy confronts combines at least two elements: (1) mythological narratives, possibly the kind of speculative elaboration of biblical stories found in Jewish pseudepigrapha (the Book of Jubilees, 1 Enoch, and later rabbinic midrash all elaborated biblical genealogies and narratives); (2) genealogical speculation, which in later Gnostic systems involved elaborate chains of divine emanations (<em>aeons</em>). The phrase 'promoting speculations rather than stewardship of God' (<em>oikonomian theou</em>) sets productive household-management against idle theory.</p>",
    "5": "<p>'The goal of this instruction is love from a pure heart and good conscience and sincere faith' — Paul identifies the <em>telos</em> (goal, end-purpose) of the entire teaching enterprise as love, not correct doctrine per se. The triad 'pure heart / good conscience / sincere faith' is a Hebrew-influenced anthropological vocabulary: the heart (<em>kardia</em>) as the seat of will and intention, the conscience (<em>syneidēsis</em>) as the internal moral monitor (a Stoic concept Paul adopted), and faith (<em>pistis</em>) as the trusting relationship with God. The false teachers have missed all three.</p>",
    "6": "<p>'Meaningless talk' (<em>mataiologia</em>) — the word appears in Hellenistic moral philosophy for empty, purposeless speech; the Stoics criticized <em>adoleschia</em> (chatter) as a vice. The contrast between substantive speech aimed at love and edification versus aimless verbal speculation runs through Hellenistic Jewish and early Christian moral instruction (Jas 3:1-12; Eph 4:29; Col 4:6). The false teachers have drifted into precisely the kind of discourse the Stoics also deplored, but Paul's criterion of judgment is Christological rather than rational.</p>",
    "7": "<p>'Wanting to be teachers of the law' (<em>nomodidaskaloi</em>) — the false teachers have Jewish or Judaizing tendencies; they want authoritative Torah-teacher status. The term <em>nomodidaskalos</em> appears in Luke 5:17 and Acts 5:34 for recognized Jewish Torah authorities. The irony Paul exposes: they want the authority of Torah-teachers while not understanding what the Torah says or why it was given. The Ephesian false teaching seems to be a Jewish-speculative rather than purely Gnostic phenomenon.</p>",
    "8": "<p>'The law is good if one uses it properly' (<em>nomimōs</em>) — Paul's nuanced Torah-theology holds together two claims: the law is good (affirming its divine origin and character, Rom 7:12) and the law can be misused. <em>Nomimōs</em> (lawfully, properly) is an adverb from the legal sphere; using the law lawfully means using it for its intended purpose: exposing sin and driving the sinner to Christ (Gal 3:24), not speculative elaboration or as a mechanism of merit.</p>",
    "9": "<p>The vice list of vv. 9-10 is a standard Hellenistic literary form — the <em>katalogos kakōn</em> (list of evils) found in Stoic, Platonic, and Jewish moral literature (Philo, Decal. 168-173; Wis 14:25-26; Rom 1:29-31). Paul's specific list maps loosely to violations of the Decalogue's second table: lawbreakers/rebels → fifth commandment (honor parents implies authority); murderers → sixth; sexually immoral → seventh; slave traders → eighth (kidnapping persons); perjurers → ninth. The law functions diagnostically, naming transgression, not constructively as a ladder of merit.</p>",
    "10": "<p>'Slave traders' (<em>andrapodistai</em>) — kidnapping persons for sale into slavery was a significant industry in the Roman world; Paul's inclusion of it in the vice list reflects both the moral seriousness of the act and the OT prohibition (Exod 21:16: whoever steals a man and sells him shall be put to death). The Roman economy ran on enslaved labor (estimated 20-35% of the Italian population); the church in Corinth, Ephesus, and elsewhere included both enslaved people and slaveholders. The vice list does not critique the institution as such but names kidnapping as the extreme manifestation of the love-of-money root.</p>",
    "11": "<p>'The gospel concerning the glory of the blessed God, which he entrusted to me' — Paul's self-description as the entrusted bearer of the gospel establishes the authority behind the entire letter: he does not merely convey opinions but a <em>parathēkē</em> (deposit, trust) from God. The 'blessed God' (<em>makarios theos</em>) uses a term (<em>makarios</em>) that Greek philosophy applied to the gods in their state of undisturbed beatitude; Paul applies it to the God who acts redemptively in history — blessedness that is active, not passive.</p>",
    "12": "<p>Paul's thanksgiving for his own conversion and appointment: 'he considered me trustworthy, appointing me to his service' (<em>diakonia</em>). The language of divine appointment (<em>themenos eis diakonian</em>) echoes prophetic-call narratives (Jer 1:5; Isa 49:1-6) and Paul's own account in Gal 1:15-16. Paul's conversion ca. 33-35 CE is the biographical anchor of his apostolic identity; the Pastoral Epistles use it as a paradigmatic narrative of grace overcoming the worst sinner.</p>",
    "13": "<p>'A blasphemer and a persecutor and a violent man' (<em>blasphēmon kai diōktēn kai hybristēn</em>) — Paul's self-description summarizes Acts 8:1-3 and 9:1-2; he voted to execute Stephen (Acts 26:10), imprisoned believers, and attempted to force them to blaspheme (Acts 26:11). The three terms escalate: blasphemy against the name, systematic persecution, and violent force (<em>hybristēs</em> = one who violates others with contemptuous force, a term of strong moral opprobrium in both Greek and Roman ethical discourse). 'I acted ignorantly in unbelief' (<em>agnoōn</em>) echoes the Torah distinction between sins committed in ignorance (Lev 4:2; Num 15:22-31) and high-handed sins requiring excision.</p>",
    "14": "<p>'The grace of our Lord was poured out on me abundantly' (<em>hyperepleonasen</em>) — the verb is a Pauline coinage (hapax), a double-compound meaning to super-abound, to overflow beyond measure. The Damascus road experience reshaped Paul's entire theological vocabulary: grace replaced law-observance as the operative category of relationship with God. The pairing 'faith and love that are in Christ Jesus' summarizes the new relational coordinates — both are located 'in Christ,' the phrase that appears over 80 times in Paul's letters as the shorthand for the sphere of the new creation.</p>",
    "15": "<p>The first of the Pastoral Epistles' five 'faithful sayings' (<em>pistos ho logos</em>): a recognized formula introducing pre-formed Christian tradition. The five faithful sayings are: 1 Tim 1:15 (Christ came to save sinners); 1 Tim 3:1 (seeking the oversight is a good work); 1 Tim 4:8-9 (godliness holds promise for the present and the future life); 2 Tim 2:11-13 (if we die with him, we will live with him); Tit 3:8 (those who believe should be devoted to good works). These appear to be early creedal or catechetical formulae that the Pastoral Epistles preserve.</p>",
    "16": "<p>'That in me, the worst of sinners, Christ Jesus might display his perfect patience' (<em>endeixētai hypotypōsin</em>) — <em>hypotypōsis</em> is a technical term from ancient rhetoric and education meaning 'pattern,' 'sketch,' or 'model' — the preliminary outline that an artist or teacher produces to be copied. Paul is the pattern (prototype) for future believers: if Christ's patience could encompass the conversion of the chief of sinners, it can encompass any sinner. This argument from Paul's conversion as a limiting-case example is a standard form of Jewish and Hellenistic proem argument.</p>",
    "17": "<p>The doxology — 'to the King eternal, immortal, invisible, the only God' — draws on a conventional Hellenistic Jewish form for ending a section of praise (cf. Rom 11:33-36; 16:25-27; Jude 24-25). The attributes are Greek philosophical predications of the divine: immortal (<em>aphthartos</em>), invisible (<em>aoratos</em>), only (<em>monos</em>). The four terms together — King / eternal / immortal / invisible — contrast the God of Israel with both the Roman emperor (mortal, visible, temporal) and with the speculative aeons of the false teachers' genealogies (multiple, generated).</p>",
    "18": "<p>'Prophecies once made about you' (<em>tas proagonousas epi se prophēteias</em>) — Timothy's commissioning was accompanied by charismatic prophetic words (cf. 4:14: prophetic utterance when the body of elders laid their hands on you; 2 Tim 1:6: the gift of God that is in you through the laying on of my hands). This prophetic commissioning practice has analogies in the OT (the elders who prophesied in Num 11:25) and in early Christian order (Acts 13:1-3: the Antioch community's prophetic commissioning of Paul and Barnabas). The prophecies are now the basis of Timothy's mandate to fight the good fight.</p>",
    "19": "<p>'Suffering shipwreck with regard to the faith' (<em>enaupagēsan</em>) — the nautical metaphor of shipwreck for moral or spiritual collapse appears in Hellenistic moral literature (Epictetus, Diss. 2.18.17; Philo, Cher. 8). In a culture where sea travel was both essential and genuinely dangerous (Paul himself survived three shipwrecks, 2 Cor 11:25), the metaphor had immediate visceral force. The 'good conscience' (<em>agathē syneidēsis</em>) held alongside faith is the Stoic concept of moral self-awareness applied as a pastoral virtue: abandon it and the ship founders.</p>",
    "20": "<p>Hymenaeus and Alexander — two named opponents whom Paul has 'handed over to Satan' (<em>paredōka tō satana</em>). The same formula appears in 1 Cor 5:5 for the Corinthian man living with his father's wife: the excommunication formula where removing the offender from the community's protection is described as returning them to Satan's domain (the world outside the church). The purpose is corrective: 'so that they may learn not to blaspheme' — discipline aimed at restoration. Hymenaeus reappears in 2 Tim 2:17 (saying the resurrection has already happened); Alexander may be the same as the coppersmith of 2 Tim 4:14.</p>"
  },
  "2": {
    "1": "<p>Four prayer terms — <em>deēseis</em> (petitions, urgent requests), <em>proseuchai</em> (prayers, the general term), <em>enteuxeis</em> (intercessions, the term for petitioning a superior on behalf of another; used of access to a king), <em>eucharistiai</em> (thanksgivings) — are likely a comprehensive rather than precisely differentiated list: all forms of prayer, without exception, for all people. The Hellenistic religious vocabulary Paul uses is drawn from both the synagogue liturgical tradition (the Amidah's 18 benedictions) and the vocabulary of petitioning the emperor or a patron through formal request channels.</p>",
    "2": "<p>'For kings and all those in authority' — praying for the welfare of foreign rulers was known in Jewish diaspora practice: Jeremiah commanded the exiles to seek the welfare of Babylon (Jer 29:7); the Jerusalem temple offered daily sacrifices for the Roman emperor (Josephus, BJ 2.197); Philo documents Caligula's withdrawal of this benefit as an act of aggression. The motivation — 'that we may live peaceful and quiet lives' (<em>ēremon kai hēsychion bion</em>) — is pragmatic civic theology: Christian communities benefited from Roman order and the rule of law; they prayed for the authority structures that enabled the gospel's spread.</p>",
    "3": "<p>'God our Savior' (<em>theos sōtēr hēmōn</em>) — the title <em>sōtēr</em> (Savior) was a standard honorific in the Hellenistic world for rulers who delivered their people from danger or brought prosperity: Ptolemy I was called Savior, Augustus was hailed as sōtēr throughout the eastern Mediterranean. The Pastoral Epistles' repeated use of the title for God the Father and Christ Jesus is a deliberate counter-claim: the real Savior is not Caesar but the God who created all people and wills their salvation (v. 4).</p>",
    "4": "<p>'Who wants all people to be saved and to come to a knowledge of the truth' (<em>pantas anthrōpous thēlei sōthēnai</em>) — the universal salvific will is consistent with the universal prayer mandate of v. 1 (pray for all) and the universal ransom of v. 6 (Christ gave himself for all). Theologians have long discussed whether this is a sincere antecedent will (God genuinely wishes all to be saved) or a general will qualified by election. The pastoral context uses it as the basis for universal intercession: because God wills all to be saved, we pray for all without discrimination — Roman emperors included.</p>",
    "5": "<p>'One God and one mediator' — the dual monotheistic claim challenges the polytheistic intermediary system of Greco-Roman religion (multiple gods, divine hierarchies, intermediary daimones) and possibly the emerging Gnostic scheme of successive divine emanations through which prayers ascend. In the Hellenistic world, achieving access to higher deities often required intermediary beings; Paul concentrates all mediation in the one man Christ Jesus, whose humanity is the instrument of access. The singular mediator claim is simultaneously anti-polytheistic and anti-Gnostic.</p>",
    "6": "<p>'Himself as a ransom for all (<em>antilytron hyper pantōn</em>) — witnessed to at the proper time (<em>kairois idiois</em>).' The phrase <em>kairois idiois</em> (at its own/proper times) is a distinctive Pastoral Epistles formula (also 6:15; Tit 1:3) indicating that the Christ-event occurred at the divinely appointed moment in history — not by accident but by plan. The Hellenistic philosophical tradition also used <em>kairos</em> for the opportune, decisive moment; Paul's use gives the Incarnation the character of a cosmic kairos.</p>",
    "7": "<p>'A herald (<em>kēryx</em>) and apostle and teacher of the Gentiles in faith and truth' — the <em>kēryx</em> (herald) is the public announcer who carries a message from an authority; in Greek civic life the herald was an official messenger whose person was inviolable. Paul adopts this civic metaphor for his apostolic role: he carries a message not his own, with the authority of the one who sent him. The parenthesis 'I am telling the truth, I am not lying' (<em>alētheian legō, ou pseudomai</em>) mirrors the oath formula of Rom 9:1 — a solemn asseveration about a matter of special importance.</p>",
    "8": "<p>'Men everywhere to pray, lifting up holy hands without anger or disputing' — the orans posture (hands raised, palms outward) was the standard prayer posture in both Jewish and Greco-Roman antiquity; the Psalms describe it (Ps 28:2; 134:2: lift your hands to the sanctuary); Roman prayer typically involved the same raised-hand gesture. The requirement 'without anger or disputing' reflects the context: the false teachers in Ephesus were generating controversy; prayer offered in that spirit is disqualified. Ritual posture and interior disposition must align.</p>",
    "9": "<p>'Women to dress modestly, with decency and propriety, not with braided hair and gold or pearls or costly attire' — the critique of ostentatious feminine display was a standard topos in Greco-Roman moral literature (Juvenal, Sat. 6; Plutarch, <em>Coniug. Praec.</em> 141e-f; Livy 34.1-8 on the Lex Oppia; Philo on women's dress). The specific items — braided hair (<em>plokais</em>), gold (<em>chrysō</em>), pearls (<em>margaritais</em>) — were markers of wealth and status in Roman urban culture; their rejection calls for visible social leveling within the assembly.</p>",
    "10": "<p>'Good deeds, appropriate for women who profess to worship God' — the alternative adorning is the social visibility of good works, which in the Greco-Roman world carried significant honor (<em>timē</em>). The women who supported Jesus's ministry (Luke 8:1-3), the patronesses of Paul's churches (Phoebe as <em>prostatis</em>, Rom 16:1-2; Lydia, Acts 16:15), and the widows known for their good deeds (5:10) model what this looks like in practice. The instruction redirects the social energy of status display toward community service.</p>",
    "11": "<p>'A woman should learn in quietness (<em>hēsychia</em>) and full submission' — the novelty of this instruction, often missed, is the imperative that women should <em>learn</em> at all. In the first-century Greco-Roman world, women's education was informal and domestic; the synagogue did not formally teach women Torah. Philo and later rabbinic sources show that women were not expected to attend public instruction. Paul's instruction that women should learn — even qualified by 'in quietness' — is itself an expansion of women's participation in formal religious instruction relative to contemporary practice.</p>",
    "12": "<p>'I do not permit a woman to teach or to exercise authority over a man' (<em>didaskein de gynaiki ouk epitrepō, oude authentein andros</em>) — <em>authentein</em> (translated 'exercise authority') is a hapax legomenon in the NT; its semantic range in contemporary papyri and literature includes both neutral senses (to have authority) and more negative ones (to domineer, to usurp). The interpretive question — whether this is a universal principle or a culturally-specific response to the false teaching in Ephesus that was spreading through women in the community (5:13; 2 Tim 3:6-7) — has generated extensive debate in biblical scholarship.</p>",
    "13": "<p>'For Adam was formed first, then Eve' — the creation order argument appeals to Genesis 2:7-22, where Adam's prior formation is narrated before Eve's. The use of Genesis 2 rather than Genesis 1 (where male and female are created simultaneously) is deliberate: the Genesis 2 sequence is treated as establishing a pattern of relational priority. Paul uses the same Genesis 2 sequence in 1 Cor 11:8-9 in a different but related argument about head-coverings. The appeal to creation order grounds the instruction in protological rather than cultural foundations.</p>",
    "14": "<p>'Adam was not the one deceived; it was the woman who was deceived and became a transgressor' — Paul distinguishes the mode of transgression: Adam was not deceived (<em>ouk ēpatēthē</em>) but acted with open-eyed disobedience; Eve was thoroughly deceived (<em>exapatētheisa</em>). This reading of Genesis 3 has parallels in Jewish interpretive tradition (Philo, <em>Opif.</em> 165; <em>Leg. All.</em> 3.59; Sirach 25:24: from a woman sin had its beginning) but differs from the dominant reading in Romans 5:12-21 where Adam is the primary agent of sin's entry. The Pastoral Epistles' use of the Eve-deception narrative in the context of women being deceived by false teachers in Ephesus (2 Tim 3:6-7) suggests a contextual rather than universal application.</p>",
    "15": "<p>'But women will be saved through the childbearing' (<em>dia tēs teknogonias</em>) — the article before 'childbearing' is significant: it may point to a specific childbearing, i.e., the Incarnation (the woman who bore the Christ), rather than childbearing in general. Alternatively, 'saved through childbearing' has been read as: (1) preserved safely through the dangers of childbirth if they continue in faith; (2) women's salvation comes through their role as mothers (a social-functional reading); (3) through the birth of the Messiah, women share in salvation. The conditional 'if they continue in faith, love, and holiness with self-control' shifts the focus to the ongoing character required for salvation, suggesting the 'through' is instrumental rather than meritorious.</p>"
  },
  "3": {
    "1": "<p>The second of the faithful sayings: 'Whoever aspires to be an overseer desires a noble task.' The <em>episkopos</em> (overseer/bishop) in first-century usage was a function-title for a superintendent or supervisor — used in civic administration (guild overseers), in the LXX for officers of the temple and community (Neh 11:9), and in the Qumran community for the <em>mebaqger</em> (inspector). The use of <em>episkopos</em> for Christian community leaders appears to be emerging in the Pauline period (Phil 1:1; Acts 20:28); Ignatius of Antioch (early 2nd century) will establish the threefold order of bishop/elder/deacon.</p>",
    "2": "<p>'Husband of one wife' (<em>mias gynaikos andra</em>, literally: 'a one-woman man') — the phrase has been interpreted as: (1) prohibition of polygamy (unusual in the Roman Empire but practiced among some Jews); (2) prohibition of remarriage after divorce; (3) prohibition of remarriage after a spouse's death; (4) a positive requirement of marital fidelity rather than a ban on remarriage. The most natural reading in the Roman context is option 4: a man known for unswerving devotion to one woman, in contrast to the Roman cultural acceptance of concubinage and the double sexual standard. The other qualifications — temperate, self-controlled, respectable, hospitable, able to teach — map onto Greco-Roman ideals of the excellent <em>paterfamilias</em>.</p>",
    "3": "<p>'Not given to drunkenness' (<em>mē paroinon</em>) — drunkenness was a standard disqualifier in Greco-Roman and Jewish moral literature. The Hellenistic philosophical tradition (Stoics especially) treated self-mastery (<em>enkrateia</em>) and sobriety as foundational virtues; Plato's <em>Laws</em> (1.637e-638a) discussed when wine was appropriate; Philo wrote against drunkenness extensively (<em>De Ebrietate</em>). The qualification for the overseer runs parallel to Hellenistic civic-honor standards: the man who holds community office must be above reproach in the precisely those vices that disqualify a person from public trust.</p>",
    "4": "<p>'Managing his own household well' (<em>tou idiou oikou kalōs proistamenon</em>) — the household-management qualification is the pivot of the overseer's qualifications. The Hellenistic moral tradition (Aristotle, <em>Pol.</em> 1.1-2; Xenophon, <em>Oec.</em>; Philo, <em>Decal.</em>; Pseudo-Plutarch, <em>Lib. Ed.</em>) treated the management of the household (<em>oikonomia</em>) as the training ground for political and civic leadership. The early church's house-church structure made this more than an analogy: the overseer literally hosted and managed a house church, so household-management competence was a direct prerequisite for the role.</p>",
    "5": "<p>'If someone does not know how to manage his own household, how will he take care of God's church?' — the <em>a fortiori</em> argument from household to church uses Hellenistic administrative logic: the smaller unit (household) trains for and anticipates the larger (civic/church community). The church (<em>ekklēsia</em>) as God's household (<em>oikos theou</em>, v. 15) makes this not merely analogical but structural: the church is organized like an expanded household, and the overseer manages it as a <em>paterfamilias</em> manages his home.</p>",
    "6": "<p>'Not a recent convert' (<em>neophyton</em> — literally 'newly planted,' a horticultural metaphor) — a designation for a new Christian that became the technical term neophyte. The concern is that a recently converted person lacks the tested character that public leadership requires. The danger is 'puffed up with conceit' (<em>typhōtheis</em>, literally 'wrapped in smoke/mist,' hence inflated with pride) — the same word is used in 6:4 for the false teachers. The 'judgment of the devil' (<em>krima tou diabolou</em>) is ambiguous: the judgment that the devil fell under (pride → fall), or the judgment the devil pronounces.</p>",
    "7": "<p>'A good reputation with outsiders' (<em>martyrian kalēn echein apo tōn exōthen</em>) — Roman civic culture operated on an elaborate system of honor and shame in which public reputation (<em>fama</em>, <em>existimatio</em>) was essential for those holding public office. The overseer's leadership of the community had public visibility; a leader whose business conduct, household management, or social behavior was locally disreputable would bring shame on the community he represented. The 'snare of the devil' (<em>pagida tou diabolou</em>) refers to the destructive entanglement that a compromised reputation produces.</p>",
    "8": "<p>Deacons (<em>diakonoi</em> — servants, ministers) — the role is attested in Phil 1:1 (alongside overseers) and appears to have developed from the functional role of table-servers and practical servants of the community (Acts 6:1-6, though the seven are not called deacons there). By the time of the Pastoral Epistles, deacons are a recognized order with qualifications parallel to (but somewhat less stringent than) the overseers'. 'Not indulging in much wine' and 'not pursuing dishonest gain' (<em>mē aischrokerdeis</em>) suggest roles that involved both social occasions (meals) and the administration of community finances.</p>",
    "9": "<p>'The mystery of the faith' (<em>to mystērion tēs pisteōs</em>) — <em>mystērion</em> in Paul's usage is not a secret cult secret but the once-hidden, now-revealed divine plan centered on Christ (Rom 16:25; Eph 3:3-6; Col 1:26-27). The deacon must hold this revealed mystery with a 'clear conscience' — the Stoic moral-monitor concept applied now to doctrinal fidelity. The combination of intellectual grasp (holding the mystery) and moral integrity (clear conscience) parallels the overseer's requirement of both household competence and teaching ability.</p>",
    "10": "<p>'Let them first be tested' (<em>dokimazesthōsan prōton</em>) — the testing of candidates before installation is a form of the civic scrutiny (<em>dokimasia</em>) that Athenian democracy required of candidates for public office; those who passed the scrutiny were then installed. The church adapts the civic form: doctrinal and moral screening precedes formal installation as a deacon. 'If there is nothing against them' (<em>anenkletoi ontes</em>) — the same legal vocabulary of blamelessness used for the overseer (v. 2).</p>",
    "11": "<p>'Women likewise' (<em>gynaikas hōsautōs</em>) — the Greek is ambiguous: are these the wives of deacons, or female deacons (deaconesses)? The absence of the possessive pronoun ('their wives' would more naturally be <em>tas gynaikas autōn</em>) suggests these may be women in a parallel diaconal role. The existence of female deacons is attested by Pliny the Younger (ca. 112 CE) who reports torturing two female Christian slaves who were called <em>ministrae</em> (the Latin equivalent of <em>diakonoi</em>). Phoebe is described as a <em>diakonos</em> of the church at Cenchreae in Rom 16:1.</p>",
    "12": "<p>'A deacon must be faithful to his wife and manage his children and his household well' — the parallel to the overseer's qualifications (v. 2, 4) is deliberate: the same household-management criterion applies to both offices, but the deacon's qualifications are described more briefly. The deacon is a servant-leader whose domestic integrity qualifies the public service; the church's organizational logic consistently treats the household as the microcosm of the community.</p>",
    "13": "<p>'Those who have served well gain an excellent standing (<em>bathmon kalon</em>) and great boldness (<em>parrēsian pollēn</em>) in the faith in Christ Jesus' — <em>bathmos</em> (step, standing) may refer to a liturgical or social rank within the assembly; the Hellenistic military used it for rank in a hierarchy. <em>Parrēsia</em> (boldness, freedom of speech) is a key Hellenistic civic virtue — the frank speech of a free citizen; in early Christian usage it describes the confident approach to God in prayer (Heb 4:16) and bold proclamation before hostile audiences (Acts 4:29). Faithful diaconal service produces the confidence that comes from proven trustworthiness.</p>",
    "14": "<p>'Although I hope to come to you soon, I am writing you these instructions' — the <em>Briefsteller</em> (letter-writing) convention in Hellenistic correspondence included a standard element of explaining why one writes rather than visits (cf. Cicero's letters; Seneca, <em>Ep.</em> 1.1). The letter substitutes for personal presence, conveying authority and instruction in the author's absence. The Pastoral Epistles' self-presentation as letters sent in lieu of the apostle's presence fits this convention exactly; whether Paul wrote them or a later Pauline school composed them in his name, the convention is intentionally deployed.</p>",
    "15": "<p>'God's household (<em>oikos theou</em>), which is the church of the living God, the pillar and buttress of truth' — the three designations: (1) God's household — the community as family under the Father's care; (2) the church (<em>ekklēsia</em>) of the living God — the covenant assembly with a living, acting God at its center, contrasted with the dead gods of the surrounding culture; (3) the pillar and buttress (<em>stylon kai hedraiōma</em>) of truth — the architectural metaphor: as pillars support a structure, the church upholds and maintains the truth of the gospel. The 'pillar' metaphor recalls Gal 2:9 where James, Peter, and John are called 'pillars' of the Jerusalem church.</p>",
    "16": "<p>The 'mystery of godliness' hymn (v. 16b) is likely a pre-Pauline Christological confession used in worship, structured in three couplets: flesh/Spirit, angels/nations, world/glory. The parallel structure (antithetic and climactic) suggests liturgical use. The textual variant 'he was manifested' vs. 'God was manifested' (the difference between <em>hos</em> and <em>theos</em> — a one-letter difference easily confused in Greek manuscript transmission) is one of the most discussed text-critical questions in the NT; the external evidence slightly favors <em>hos</em> (who/he), while the internal argument for <em>theos</em> (God manifested in flesh) as a later theological heightening is strong.</p>"
  },
  "4": {
    "1": "<p>'The Spirit clearly says that in later times some will abandon the faith' (<em>en hysterois kairois apostēsontai tines tēs pisteōs</em>) — the explicit attribution to the Spirit's prophetic utterance recalls Jesus's eschatological warnings about false teachers (Matt 24:11, 24) and Paul's farewell speech to Ephesian elders at Miletus (Acts 20:29-30: after my departure fierce wolves will come in). The 'later times' (<em>hysteroi kairoi</em>) are not a distant future but the present era of the church — the 'already' of the last days. The false teaching being addressed is the present fulfillment of this Spirit-given warning.</p>",
    "2": "<p>'Seared consciences' (<em>kekaustriasmenōn tēn idian syneidēsin</em>) — the medical metaphor of cauterization; <em>kaustriazo</em> means to brand with a hot iron. The conscience cauterized beyond feeling maps onto the Stoic philosophical category of the person who has so deadened their moral perception that they no longer respond to moral stimuli. Epictetus (Diss. 2.22.6-7) describes the person of debased character as having lost the faculty of self-recognition. The false teachers have suppressed their moral self-monitoring through habitual hypocrisy until it no longer functions.</p>",
    "3": "<p>'Forbidding marriage and commanding abstinence from foods' — two ascetic practices that signal a dualistic theology: if matter (the body, physical relationships, food) is evil or spiritually dangerous, then marriage and eating are to be avoided. This matches the profile of emerging Gnostic and Encratite movements of the late first and second centuries (Tatian, Marcion, the Valentinians all had food/marriage prohibitions). It may also reflect a rigorous Jewish-ascetic tradition (cf. the Therapeutae whom Philo describes in <em>De Vita Contemplativa</em>). Paul's counter-argument is creation theology: God created marriage and food; creation is good; gratitude reception, not rejection, is the proper response.</p>",
    "4": "<p>'Everything God created is good, and nothing is to be rejected if received with thanksgiving' — Paul's appeal to creation goodness (Gen 1: God saw that it was good) is also Paul's counter to Gnostic body-denial. The same argument appears in Rom 14 (do not condemn what God has made) and 1 Cor 10:25-30 (eat whatever is sold in the market; give thanks to God). The Gentile mission's rejection of food laws was itself grounded in creation theology: the categories of clean/unclean belong to the Mosaic economy; creation itself is uniformly good.</p>",
    "5": "<p>'Sanctified by the word of God and prayer' — the 'word of God' that sanctifies food is either the creation blessing of Gen 1 (declaring food good) or the dominical word (Matt 15:11: not what goes in the mouth defiles) or the prayer of thanksgiving that invokes God's name over food. Jewish table-grace practice (the Birkat ha-Mazon and the blessings before eating) already treated prayer as the act that consecrated food for holy use; the early church's table-prayer inherited this practice and extended it universally regardless of the food's ritual status.</p>",
    "6": "<p>'A good minister (<em>diakonos</em>) of Christ Jesus, nourished on the words of the faith and of the good doctrine' — Timothy is described using the same servant-title as the formal office of deacon (3:8), but here as a description of his apostolic servanthood rather than a formal office. The image of being 'nourished' (<em>entrephomenos</em> — raised on, fed on) treats the words of faith as food that sustains the minister; the metaphor of Scripture as food appears in Deut 8:3 (man does not live by bread alone but by every word from God's mouth) and is developed in Jer 15:16 (your words were found and I ate them).</p>",
    "7": "<p>'Godless myths and old wives' tales' (<em>tous bebēlous kai graōdeis mythous</em>) — the double pejorative: <em>bebēlous</em> (profane, secular) dismisses the myths as lacking sacred character; <em>graōdeis</em> (old-wifely) was a standard derogatory dismissal in Hellenistic philosophy for folk superstition and unphilosophical stories. Plato used the term (<em>Gorg.</em> 527a; <em>Rep.</em> 350e) to dismiss myths not fit for serious discourse. Paul's use is polemical rather than gender-specific: it signals the myths' intellectual triviality relative to the 'words of faith and good doctrine.'</p>",
    "8": "<p>'Physical training (<em>sōmatikē gymnasia</em>) has some value, but godliness (<em>eusebeia</em>) has value for all things' — the Hellenistic gymnasium was a central civic institution, especially in cities with significant Greek cultural influence like Ephesus; the gymnasium combined athletic training with education and was associated with the formation of ideal Greek male citizenship. Paul grants the gymnasium culture its limited worth — physical training is genuinely beneficial — but subordinates it to the training of godliness, which yields benefit not only for this life but also for the coming one.</p>",
    "9": "<p>'This is a trustworthy saying and deserves full acceptance' — the third (or fourth, depending on the count) faithful saying formula. The content it introduces (or summarizes, if it looks back to v. 8) is the eschatological promise attached to godliness: 'holding promise for the present life and also for the life to come.' The dual promise — present and future — parallels the Stoic claim for virtue as the single good that benefits in all circumstances, but Paul's eschatological horizon extends the benefit beyond death in a way Stoicism could not.</p>",
    "10": "<p>'We labor and press on under reproach' (<em>kopōmen kai agōnizometha hoti ēlpikamen</em>) — the double labor-metaphor: <em>kopiaō</em> (toil, the same word Paul uses for his tent-making and apostolic labor) and <em>agōnizomai</em> (struggle, the athletic metaphor for the effort of competition). The reason for the labor is eschatological hope 'in the living God, who is the Savior of all people, especially of those who believe' — a statement that distinguishes the universal scope of potential salvation from the actual scope of realized salvation for believers.</p>",
    "11": "<p>'Command (<em>parangellle</em>) and teach (<em>didaske</em>) these things' — the dual mandate of Timothy's role: authoritative directive and reasoned instruction. The Pastoral Epistles consistently pair authority and teaching: the church is not merely an institution of command (which might function without persuasion) nor merely a school of ideas (which might function without authority). The combination models the prophetic office: the prophet both declares authoritatively and explains convincingly.</p>",
    "12": "<p>'Don't let anyone look down on you because you are young' (<em>mēdeis sou tēs neotētos kataphroneitō</em>) — in the ancient Mediterranean, wisdom and authority were conventionally associated with age (<em>presbyteros</em>, elder, is literally 'older one'). Timothy's youth (possibly mid-30s by ancient standards, since Paul has been his mentor for over a decade; <em>neotēs</em> applied to men under 40 in some ancient usage) was a potential obstacle to his authority in a culture that deferred to elders. The instruction to 'set an example' in six areas — speech, conduct, love, faith, purity — is the response: let demonstrated character substitute for accumulated years.</p>",
    "13": "<p>'Devote yourself to the public reading of Scripture (<em>anagnōsis</em>), to exhortation (<em>paraklēsis</em>), to teaching (<em>didaskalia</em>)' — the three activities describe the synagogue worship pattern that the early church inherited: the public lection of Scripture (Neh 8:8; Luke 4:16-17; Acts 13:15 describes this as standard synagogue practice), followed by the interpretive exhortation (the sermon, <em>midrash</em> or <em>dvar Torah</em>), followed by doctrinal instruction. The Pastoral Epistles present Timothy's ministry as a continuation of this Jewish-liturgical practice, now applied to the reading of apostolic texts alongside Torah.</p>",
    "14": "<p>'The gift (<em>charisma</em>) given through prophecy with the laying on of the council of elders (<em>presbyterion</em>)' — the ordination rite described here combines two elements: prophetic designation (a charismatic word identifying Timothy's gift and ministry) and formal installation by the elders' collective laying-on of hands. In 2 Tim 1:6 it is 'through the laying on of my [Paul's] hands' — the two accounts are complementary: Paul and the eldership acted together. The <em>presbyterion</em> as a collective council of elders has parallels in the Sanhedrin (Luke 22:66; Acts 22:5) and in the Qumran community's council of elders.</p>",
    "15": "<p>'Be diligent in these matters; give yourself wholly to them' (<em>en toutois isthi</em>, literally 'be in these things') — the Stoic ideal of total devotion to one's calling; the sage who gives himself entirely to virtue without distraction. Paul applies it to the pastoral vocation: Timothy's entire being is to be immersed in the ministry he has received. 'So that everyone may see your progress (<em>prokopē</em>)' — <em>prokopē</em> was a Stoic term for moral progress toward virtue; Paul applies it to Timothy's public development in ministry, visible to the whole community.</p>",
    "16": "<p>'Watch your life (<em>seauton</em>) and doctrine (<em>didaskalia</em>) closely' — the coupling of personal character and theological content reflects the Hellenistic ideal that the teacher's life must embody the teaching; a philosopher whose life contradicted his philosophy was a hypocrite, not a sage. The Pastoral Epistles consistently treat character and doctrine as inseparable: doctrinal error tends to accompany moral failure (the false teachers are both wrong in teaching and corrupt in character). The eschatological motive — 'you will save both yourself and your hearers' — makes the personal-character requirement soteriologically weighty.</p>"
  },
  "5": {
    "1": "<p>'Do not rebuke an older man (<em>presbyterō</em>) but exhort him as a father' — <em>presbyteros</em> is ambiguous (elder as age or elder as office), but the family-metaphor context ('as a father') suggests the age-sense here: Timothy is to treat older men with the deference owed to a father, not to exercise over them the authority of a superior. The Mediterranean honor code gave the eldest generation a presumptive claim to respect and deference; the instruction applies this social norm within the church community.</p>",
    "2": "<p>'Younger women as sisters with absolute purity (<em>en pasē hagneia</em>)' — the kinship metaphor (sisters) combined with the absolute purity requirement addresses the social danger of a young male leader in pastoral relationship with women in the community. The Roman household context in which house-churches met created intimacy between leaders and community members that required the family-metaphor's protective framing. The 'absolute purity' (<em>hagneia</em>) requirement acknowledges the pastoral risk and addresses it head-on.</p>",
    "3": "<p>'Give proper recognition (<em>tima</em>) to widows who are really in need' — <em>tima</em> is the honor-code word for recognition of status; the instruction carries both social dignity and, likely, financial support (the 'double honor' of v. 17 includes remuneration). In the Roman world, widows occupied a precarious social position: without a husband's legal protection and economic support, and without a son's household to shelter in, a widow could be destitute. The early church's widow-support system was a recognizable social institution by the time of Polycarp (Phil. 4.3: widows as the altar of God) and Tertullian.</p>",
    "4": "<p>'If a widow has children or grandchildren, these should first learn to practice piety toward their own family and to make some return to their parents' — the Roman concept of <em>pietas</em> (familial duty and devotion) is the exact context here; Roman law and moral tradition required children to provide for aging parents. The Pastoral Epistles' instruction on family provision draws on this Roman social expectation and frames it as an expression of religious duty. The state had no welfare system; the family was the primary social-safety net, supplemented by voluntary associations and (now) the church for those without family.</p>",
    "5": "<p>'The widow who is truly alone has put her hope in God and continues in supplications and prayers night and day' — the portrait of the ideal widow is modeled on Anna in Luke 2:36-38 (a widow of eighty-four years who did not depart from the temple, worshiping with fasting and prayer night and day). The widowed state, freed from marital obligations, enabled total devotion to prayer — a recognized form of religious vocation in both Jewish (the Therapeutrides whom Philo describes) and early Christian communities. The term 'truly alone' (<em>memonōmenē</em>) echoes LXX Lam 1:1 (Jerusalem, sitting alone).</p>",
    "6": "<p>'The widow who lives for pleasure (<em>spatalōsa</em>) is dead while she lives' — <em>spataō</em> means to live luxuriously or wantonly; the Roman matron who was widowed at a relatively young age might enjoy considerable freedom, social visibility, and resources. The Pastoral Epistles' concern about younger widows who 'live for pleasure' (v. 6) and 'violate their first pledge' (v. 12) reflects the social reality of widowhood in the Roman Empire: the widow who used her freedom for self-indulgence rather than service was spiritually dead even while biologically alive. The paradox echoes the Pauline mortality-in-sin language of Eph 2:1-3.</p>",
    "7": "<p>'Give the people these instructions so that they may be above reproach' (<em>anepilēptoi ōsin</em>) — the same 'above reproach' vocabulary used for the overseer (3:2). The instruction about widow-support is not a private pastoral matter but public community order; its proper execution preserves the community's external reputation. The Roman world would notice and judge a community that failed to provide for its most vulnerable members; the command to 'give these instructions' makes the widow-care policy explicit and public.</p>",
    "8": "<p>'Anyone who does not provide for their own household has denied the faith and is worse than an unbeliever' (<em>apistou cheirōn estin</em>) — the shocking comparison to unbelievers turns on Roman social ethics: even pagans recognized family provision as a fundamental duty (<em>pietas</em>). A Christian who neglects family provision fails to meet even the baseline of pagan virtue; such a person has in practice denied the faith they profess. The Roman philosopher Cicero (<em>De Off.</em> 1.16.51) treated family care as one of the most natural and binding obligations of human society.</p>",
    "9": "<p>'No widow is to be enrolled (<em>katalegesthō</em>) unless she is over sixty, the wife of one husband' — the formal enrollment in a list (<em>katalogos</em>) indicates an institutionalized status: the 'enrolled widow' had both recognized standing in the community and, presumably, community financial support. The sixty-year age threshold ruled out younger widows who might remarry; the 'wife of one husband' parallels the 'husband of one wife' requirement for overseers and deacons. By the second century, the 'order of widows' (<em>taxis chērōn</em>) was a recognized liturgical institution (Ignatius, Polycarp, Tertullian).</p>",
    "10": "<p>'Well known for good works: she has brought up children, has shown hospitality, has washed the saints' feet, has cared for the afflicted' — the four good-works criteria describe the practical domestic service that characterized the enrolled widow's prior life. Foot-washing (<em>nipsen podas hagiōn</em>) was the servant's task and the host's courtesy; Jesus's washing of the disciples' feet (John 13) elevated it as a symbol of humble service. The criteria are entirely practical rather than doctrinal: the enrolled widow's qualification is a track record of concrete ministry, not theological attainment.</p>",
    "11": "<p>'Younger widows, do not enroll, for when their passions draw them away from Christ they want to marry' — the pastoral concern is practical: a young widow who takes the widow-enrollment pledge (possibly a vow of continued celibacy in service) and then remarries violates her public commitment. The social reality in Roman culture: young widows had significant marriage pressure from families and the legal incentives of the Augustan marriage laws (<em>Lex Iulia de maritandis ordinibus</em>, 18 BCE) which penalized women of childbearing age who remained unmarried.</p>",
    "12": "<p>'Bringing judgment on themselves because they have broken their first pledge' (<em>tēn prōtēn pistin ēthetēsan</em>) — whether this refers to a specific vow of widow-service or to their prior faith-commitment, the language of 'setting aside' (<em>atitheō</em>) their first faith is serious: it echoes the language of apostasy. The pastoral dilemma Paul navigates: the enrolled widow's spiritual dignity and community support vs. the practical risk of a young woman being locked into a role she may later abandon under pressure from social and familial expectations.</p>",
    "13": "<p>'Getting into the habit of going from house to house; and not only idle but gossips and busybodies, saying what they should not' — the social critique maps onto Roman satirists' stock portrait of women who circulate from household to household spreading rumors (Juvenal, <em>Sat.</em> 6). The word <em>periergoi</em> (busybodies) also appears in the Thessalonian context of eschatologically-idle believers who meddle in others' affairs rather than working (2 Thess 3:11). The common thread: eschatological excitement or social dislocation producing purposeless activity that damages community relationships.</p>",
    "14": "<p>'Counsel younger widows to marry, have children, manage their homes, and give the enemy no occasion for slander' — the practical counsel reverses the direction of v. 11-13: rather than enrolling young widows and risking scandal, direct them into the socially honored role of household manager (<em>oikodespotein</em> — to be mistress of the house). The Roman ideal of the virtuous matron who manages her household (<em>domina</em>) is here deployed as the protective role that removes the 'adversary's occasion for slander.' Paul's argument is simultaneously countercultural (valuing the domestic role) and pragmatic (reducing community vulnerability to external criticism).</p>",
    "15": "<p>'Some have already turned to follow Satan' — the trajectory of the false teachers in ch1 (Hymenaeus and Alexander, handed to Satan) is now paralleled by some of the younger widows whose behavior has moved outside community order. The Pastoral Epistles' consistent linkage of practical disorder (idleness, gossip, breaking pledges) with demonic influence is not merely rhetorical: it reflects the cosmological framework in which the community's order is maintained against the disorder of the surrounding powers.</p>",
    "16": "<p>'If any believing woman has widows in her care, let her help them' — the shift to a female patron-figure (<em>pistē</em>, believing woman) reflects the house-church reality in which wealthy women hosted and financially supported the community (Lydia, Acts 16:14-15; Phoebe, Rom 16:1-2; Nympha, Col 4:15). The instruction distributes the financial burden: family members (v. 4), household patrons (v. 16), and the church (v. 9) share the care of widows rather than defaulting everything to community funds. The economic rationality — 'so that the church may help those who are truly widows' — reflects the real resource constraints of early house-church communities.</p>",
    "18": "<p>'The worker deserves his wages' (<em>axios ho ergatēs tou misthou autou</em>) — a dominical saying (Luke 10:7; Matt 10:10: the laborer deserves his food) cited here alongside the Torah citation (Deut 25:4: do not muzzle an ox). The juxtaposition of Torah and Jesus's teaching as dual warrant for the same principle indicates that by the Pastoral period, Jesus's teaching was being cited with the same authority as Scripture. This is one of several NT passages (1 Cor 9:9-14; Luke 10:7; Matt 10:10) that converge on the legitimacy of financial support for those who labor in the gospel.</p>",
    "19": "<p>'Do not entertain an accusation against an elder unless brought by two or three witnesses' (<em>epi dyo ē triōn martyrōn</em>) — the Deuteronomic rule of multiple witnesses (Deut 19:15) is applied to elder-discipline. The rule provides protection against malicious or frivolous accusations against leaders who are natural targets of community resentment. Roman legal procedure also required witnesses; the overlap between Mosaic law and Roman legal convention strengthened the practical logic of the rule. Jesus applied the same Deuteronomic principle to community discipline in Matt 18:16.</p>",
    "20": "<p>'Those who are sinning, rebuke before all (<em>enōpion pantōn</em>), so that the rest may stand in fear' — public discipline for leaders who persist in sin follows the private witness-confrontation procedure. The public rebuke has both restorative intent (shame inducing repentance) and deterrent effect ('the rest may stand in fear'). The Roman civic censure of magistrates who abused their office had similar public dimensions; the early church's discipline process operates within the broader framework of community accountability that both Roman and Jewish practice recognized.</p>",
    "21": "<p>'I charge you before God and Christ Jesus and the elect angels' — the solemn oath-formula invokes a triple witness: God, Christ, and the angels who serve as divine attendants and witnesses (cf. Deut 32:43 LXX; Dan 7:10; Rev 5:11). 'Elect angels' (<em>ekletōn angelōn</em>) distinguishes the faithful angels from the fallen ones (cf. 1 Cor 6:3; Jude 6); they are the heavenly court before whom Timothy's faithfulness in leadership is to be maintained. The instruction 'keep these things without prejudging, doing nothing by partiality' makes the oath-setting concrete: impartial administration of elder-discipline.</p>",
    "22": "<p>'Do not be hasty in laying on of hands, and do not participate in another's sins' — the installation rite (ordination by laying on of hands) is irreversible in its social and spiritual effects; hasty installation of an unworthy candidate implicates Timothy in whatever that person subsequently does. The 'laying on of hands' is the same ordination gesture as in 4:14; here the concern is the pre-ordination screening rather than the act itself. 'Keep yourself pure' (<em>seauton hagnon tērei</em>) — the same purity-language as in the instruction about younger women (v. 2), now applied to Timothy's own spiritual integrity.</p>",
    "23": "<p>'Stop drinking only water and use a little wine because of your stomach and your frequent illnesses' — the personal medical advice is remarkable in a letter about church order. Timothy appears to have been taking a water-only diet possibly as an ascetic practice or as a response to the false teachers' food-abstinence teaching (4:3). Wine's medicinal use was standard in antiquity (Dioscorides, <em>De Materia Medica</em> 5.6 lists therapeutic uses; Hippocrates prescribed wine for various conditions); the instruction grounds bodily care as a legitimate concern. The verse also undercuts the ascetic teaching Timothy is supposed to counter: if the body's needs matter, bodily care is godly.</p>",
    "24": "<p>'The sins of some people are obvious (<em>prodēloi</em>), going before them to judgment' — the legal metaphor: some sins 'precede' (<em>proagousin</em>) their owner to the divine judgment seat, arriving before the person does; others 'follow after' (<em>epakoloutheousin</em>), catching up at the judgment. The distinction helps Timothy understand why some candidates seem unimpeachably good yet prove problematic later: their sins are hidden sins that arrive later. The point is epistemological humility: the overseer cannot always perceive moral reality accurately in the screening process, which is why the Elder-Witness rule (v. 19) and the patience of v. 22 are necessary.</p>",
    "25": "<p>'Good works are also obvious, and even those that are not obvious cannot remain hidden' — the inverse of v. 24: just as hidden sins eventually become visible, hidden good works cannot remain permanently concealed. The eschatological dimension is implied: at the divine judgment, all that is hidden will be revealed (Rom 2:16; 1 Cor 4:5). The practical pastoral comfort: Timothy need not know everything about every person now; the judgment will make all things plain. The instruction closes the elder-conduct section with an appeal to eschatological transparency as the ultimate criterion.</p>"
  }
}

if __name__ == '__main__':
    existing = load_comm('mkt-context', '1timothy')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-context', '1timothy', existing)
    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / '1timothy.json'))
    all_ok = True
    for ch in ['1', '2', '3', '4', '5']:
        missing = set(il.get(ch, {}).keys()) - set(existing.get(ch, {}).keys())
        if missing:
            print(f'  ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch {ch}: complete ({len(existing.get(ch, {}))} verses)')
    if all_ok:
        print('All verses present')
